package com.example.project9;

public final class GreetingCli {
    private static final String DEFAULT_GREETING = "Hello, world!";

    public static void main(String[] args) {
        System.out.println(buildGreeting(args));
    }

    static String buildGreeting(String[] args) {
        String name = null;
        for (int i = 0; i < args.length; i++) {
            String arg = args[i];
            if (arg.startsWith("--name=")) {
                name = arg.substring("--name=".length());
            } else if ("--name".equals(arg)) {
                if (i + 1 < args.length) {
                    name = args[++i];
                } else {
                    name = "";
                }
            }
        }
        return formatGreeting(name);
    }

    private static String formatGreeting(String name) {
        if (name == null || name.isBlank()) {
            return DEFAULT_GREETING;
        }
        return "Hello, " + name + "!";
    }

    private GreetingCli() {
    }
}

package com.example.project9;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;

class GreetingCliTest {

    @Test
    void defaultGreeting() {
        assertEquals("Hello, world!", GreetingCli.buildGreeting(new String[0]));
    }

    @Test
    void namedGreetingWithEquals() {
        assertEquals("Hello, Ada!", GreetingCli.buildGreeting(new String[]{"--name=Ada"}));
    }

    @Test
    void namedGreetingWithSeparateFlag() {
        assertEquals("Hello, Ada!", GreetingCli.buildGreeting(new String[]{"--name", "Ada"}));
    }

    @Test
    void blankNameFallsBackToDefault() {
        assertEquals("Hello, world!", GreetingCli.buildGreeting(new String[]{"--name="}));
        assertEquals("Hello, world!", GreetingCli.buildGreeting(new String[]{"--name", ""}));
        assertEquals("Hello, world!", GreetingCli.buildGreeting(new String[]{"--name", "   "}));
    }
}

